41	            <span className="co-m-resource-icon co-m-resource-icon--lg">{t('DS')}</span>
42	            <span className="co-resource-item__resource-name" data-test-id="resource-title">
43	              {name ?? dataSource?.metadata?.name}{' '}
44	            </span>
45	            {isDataSourceReady(dataSource) && (
46	              <span className="dps-resource-item__resource-status hidden-xs">
47	                <Label isCompact>{t('Ready')}</Label>
48	              </span>
49	            )}
50	          </h1>
51	          <div className="co-actions">
52	            <DataSourceActions dataSource={dataSource} />
53	          </div>
54	        </span>
55	      </div>
56	    </>
57	  );
58	};
59	
60	export default DataSourcePageTitle;

